require_once __DIR__.'/../config.php';require_once __DIR__.'/../lib/layout.php';require_once __DIR__.'/../lib/automatizacion_operativa.php';requiere_roles(['ADMIN','TI','GERENCIA','CEO','DIRECTOR'],'../');$pdo=db();$msg=null;
